242→               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
243→               ON CONFLICT(id) DO UPDATE SET
244→                 name        = excluded.name,
245→                 source      = excluded.source,
246→                 external_id = excluded.external_id,
247→                 email       = excluded.email,
248→                 phone       = excluded.phone,
