253→        .bind(&contact.id)
254→        .bind(&contact.name)
255→        .bind(&contact.source)
256→        .bind(&contact.external_id)
257→        .bind(contact.email.as_ref().map(|s| s.expose_secret().clone()))
258→        .bind(contact.phone.as_ref().map(|s| s.expose_secret().clone()))
259→        .bind(contact.stage.as_str())
260→        .bind(&metadata)
261→        .bind(contact.created_at as i64)
