// Step 1: Find the issue ID for CHA-17
const findIssue = await fetch('https://api.linear.app/graphql', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': apiKey },
  body: JSON.stringify({
    query: `{ issues(filter: { identifier: { eq: "CHA-17" } }) { nodes { id title state { name } comments { nodes { id body } } } } }`
  })
});
const issueData = await findIssue.json();
const issue = issueData?.data?.issues?.nodes?.[0];
if (!issue) { console.log("ERROR: CHA-17 not found"); process.exit(1); }
console.log(`Issue: ${issue.id} — ${issue.title}`);
console.log(`State: ${issue.state?.name}`);
console.log(`Existing comments: ${issue.comments?.nodes?.length}`);

// Check if workpad already exists
const existingWorkpad = issue.comments?.nodes?.find(c => c.body?.includes('## Workpad'));
if (existingWorkpad) {
  console.log(`Workpad comment exists: ${existingWorkpad.id}`);
} else {
  console.log('No workpad comment found');
}

const apiKey = process.env.LINEAR_API_KEY;

// Try searching for the issue differently
const res = await fetch('https://api.linear.app/graphql', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': apiKey },
  body: JSON.stringify({
    query: `{ issueSearch(query: "CHA-17", first: 5) { nodes { id identifier title state { name } } } }`
  })
});
const data = await res.json();
if (data.errors) {
  console.log("Errors:", JSON.stringify(data.errors));
}
const nodes = data?.data?.issueSearch?.nodes || [];
console.log(`Found ${nodes.length} results:`);
for (const n of nodes) {
  console.log(`  ${n.identifier}: ${n.title} [${n.state?.name}] id=${n.id}`);
}

const apiKey = process.env.LINEAR_API_KEY;
console.log("Key prefix:", apiKey?.substring(0, 15) + "...");
console.log("Key length:", apiKey?.length);

// Try with Bearer prefix
const res = await fetch('https://api.linear.app/graphql', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
  body: JSON.stringify({
    query: `{ viewer { id name } }`
  })
});
const data = await res.json();
console.log("Response:", JSON.stringify(data, null, 2));

