        let m = Matter::new(&c.id, "To Delete", PracticeArea::Other);
        let mid = m.id.clone();
        store.upsert_matter(m).await.unwrap();
        store.delete_matter(&mid).await.unwrap();
        store.delete_matter(&mid).await.unwrap();
        assert!(store.get_matter(&mid).await.unwrap().is_none());
