    sql.push_str(" ORDER BY updated_at DESC LIMIT ? OFFSET ?");

    let mut q = sqlx::query_as::<_, MatterRow>(&sql);
    if let Some(cid) = contact_id {
        q = q.bind(cid);
    }
    if let Some(s) = status {
