    38→    async fn list_filtered(
    39→        &self,
    40→        stage: Option<ContactStage>,
    41→        search: Option<&str>,
    42→        offset: u64,
    43→        limit: u64,
    44→    ) -> Result<Vec<Contact>> {
    45→        use secrecy::ExposeSecret;
    46→
    47→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
    48→        let search_lower = search.map(str::to_lowercase);
    49→        let mut out: Vec<Contact> = contacts
    50→            .values()
    51→            .filter(|c| stage.is_none_or(|s| c.stage == s))
    52→            .filter(|c| {
    53→                search_lower.as_deref().is_none_or(|term| {
    54→                    c.name.to_lowercase().contains(term)
    55→                        || c.email
    56→                            .as_ref()
    57→                            .is_some_and(|e| e.expose_secret().to_lowercase().contains(term))
    58→                        || c.phone
    59→                            .as_ref()
    60→                            .is_some_and(|p| p.expose_secret().to_lowercase().contains(term))
    61→                })
    62→            })
    63→            .cloned()
    64→            .collect();
    65→        out.sort_by_key(|c| std::cmp::Reverse(c.updated_at));
    66→        let offset = offset as usize;
    67→        let limit = limit as usize;
    68→        Ok(out.into_iter().skip(offset).take(limit).collect())
    69→    }
